// AdminServiceHandler is an implementation of the zarl.v1.AdminService service.
type AdminServiceHandler interface {
	ListPrompts(context.Context, *connect.Request[v1.ListPromptsRequest]) (*connect.Response[v1.ListPromptsResponse], error)
	CreatePrompt(context.Context, *connect.Request[v1.CreatePromptRequest]) (*connect.Response[v1.CreatePromptResponse], error)
	UpdatePrompt(context.Context, *connect.Request[v1.UpdatePromptRequest]) (*connect.Response[v1.UpdatePromptResponse], error)
	SetActivePrompt(context.Context, *connect.Request[v1.SetActivePromptRequest]) (*connect.Response[v1.SetActivePromptResponse], error)
	DeletePrompt(context.Context, *connect.Request[v1.DeletePromptRequest]) (*connect.Response[v1.DeletePromptResponse], error)
	ListPersons(context.Context, *connect.Request[v1.ListPersonsRequest]) (*connect.Response[v1.ListPersonsResponse], error)
	UpdatePerson(context.Context, *connect.Request[v1.UpdatePersonRequest]) (*connect.Response[v1.UpdatePersonResponse], error)
	DeletePerson(context.Context, *connect.Request[v1.DeletePersonRequest]) (*connect.Response[v1.DeletePersonResponse], error)
	ListPersonMemories(context.Context, *connect.Request[v1.ListPersonMemoriesRequest]) (*connect.Response[v1.ListPersonMemoriesResponse], error)
	DeletePersonMemory(context.Context, *connect.Request[v1.DeletePersonMemoryRequest]) (*connect.Response[v1.DeletePersonMemoryResponse], error)
	// Tool providers
	ListToolProviders(context.Context, *connect.Request[v1.ListToolProvidersRequest]) (*connect.Response[v1.ListToolProvidersResponse], error)
	ListRegisteredTools(context.Context, *connect.Request[v1.ListRegisteredToolsRequest]) (*connect.Response[v1.ListRegisteredToolsResponse], error)
	UpdateToolDescription(context.Context, *connect.Request[v1.UpdateToolDescriptionRequest]) (*connect.Response[v1.UpdateToolDescriptionResponse], error)
	ResetToolDescription(context.Context, *connect.Request[v1.ResetToolDescriptionRequest]) (*connect.Response[v1.ResetToolDescriptionResponse], error)
	PreviewGesture(context.Context, *connect.Request[v1.PreviewGestureRequest]) (*connect.Response[v1.PreviewGestureResponse], error)
	// Skills — versioned capability guides injected into the LLM prompt
	// per turn. Storage lives in Dolt; the admin surface lets operators
	// curate them and review LLM-authored proposals.
	ListSkills(context.Context, *connect.Request[v1.ListSkillsRequest]) (*connect.Response[v1.ListSkillsResponse], error)
	CreateSkill(context.Context, *connect.Request[v1.CreateSkillRequest]) (*connect.Response[v1.CreateSkillResponse], error)
	UpdateSkill(context.Context, *connect.Request[v1.UpdateSkillRequest]) (*connect.Response[v1.UpdateSkillResponse], error)
	DeleteSkill(context.Context, *connect.Request[v1.DeleteSkillRequest]) (*connect.Response[v1.DeleteSkillResponse], error)
	ListSkillProposals(context.Context, *connect.Request[v1.ListSkillProposalsRequest]) (*connect.Response[v1.ListSkillProposalsResponse], error)
	ReviewSkillProposal(context.Context, *connect.Request[v1.ReviewSkillProposalRequest]) (*connect.Response[v1.ReviewSkillProposalResponse], error)
	// Prompt templates — operator-editable Go-code-default content
	// strings used for report frontmatter, report header, report
	// footer, and future handler prompts.
	ListPromptTemplates(context.Context, *connect.Request[v1.ListPromptTemplatesRequest]) (*connect.Response[v1.ListPromptTemplatesResponse], error)
	UpdatePromptTemplate(context.Context, *connect.Request[v1.UpdatePromptTemplateRequest]) (*connect.Response[v1.UpdatePromptTemplateResponse], error)
	ResetPromptTemplate(context.Context, *connect.Request[v1.ResetPromptTemplateRequest]) (*connect.Response[v1.ResetPromptTemplateResponse], error)
	UpdateToolProvider(context.Context, *connect.Request[v1.UpdateToolProviderRequest]) (*connect.Response[v1.UpdateToolProviderResponse], error)
	CreateToolProvider(context.Context, *connect.Request[v1.CreateToolProviderRequest]) (*connect.Response[v1.CreateToolProviderResponse], error)
	DeleteToolProvider(context.Context, *connect.Request[v1.DeleteToolProviderRequest]) (*connect.Response[v1.DeleteToolProviderResponse], error)
	// Tool call history
	ListToolCalls(context.Context, *connect.Request[v1.ListToolCallsRequest]) (*connect.Response[v1.ListToolCallsResponse], error)
	GetToolCallStats(context.Context, *connect.Request[v1.GetToolCallStatsRequest]) (*connect.Response[v1.GetToolCallStatsResponse], error)
	// Voice settings
	GetVoiceSettings(context.Context, *connect.Request[v1.GetVoiceSettingsRequest]) (*connect.Response[v1.GetVoiceSettingsResponse], error)
	SetVoiceSettings(context.Context, *connect.Request[v1.SetVoiceSettingsRequest]) (*connect.Response[v1.SetVoiceSettingsResponse], error)
	PreviewVoice(context.Context, *connect.Request[v1.PreviewVoiceRequest]) (*connect.Response[v1.PreviewVoiceResponse], error)
	// Agent name — the spoken name the agent uses for itself. Injected into
	// the active prompt as {{agent_name}} so TTS pronunciation stays stable.
	GetAgentName(context.Context, *connect.Request[v1.GetAgentNameRequest]) (*connect.Response[v1.GetAgentNameResponse], error)
	SetAgentName(context.Context, *connect.Request[v1.SetAgentNameRequest]) (*connect.Response[v1.SetAgentNameResponse], error)
	// Agent avatar — the GLB model used on the immersive conversation screen.
	GetAgentAvatar(context.Context, *connect.Request[v1.GetAgentAvatarRequest]) (*connect.Response[v1.GetAgentAvatarResponse], error)
	SetAgentAvatar(context.Context, *connect.Request[v1.SetAgentAvatarRequest]) (*connect.Response[v1.SetAgentAvatarResponse], error)
	// Tasks
	ListTasks(context.Context, *connect.Request[v1.ListTasksRequest]) (*connect.Response[v1.ListTasksResponse], error)
	CancelTask(context.Context, *connect.Request[v1.CancelTaskRequest]) (*connect.Response[v1.CancelTaskResponse], error)
	DeleteTask(context.Context, *connect.Request[v1.DeleteTaskRequest]) (*connect.Response[v1.DeleteTaskResponse], error)
	// Task provider settings
	GetTaskProviderSettings(context.Context, *connect.Request[v1.GetTaskProviderSettingsRequest]) (*connect.Response[v1.GetTaskProviderSettingsResponse], error)
	UpdateTaskProviderSettings(context.Context, *connect.Request[v1.UpdateTaskProviderSettingsRequest]) (*connect.Response[v1.UpdateTaskProviderSettingsResponse], error)
	// Conversation LLM settings
	GetConversationLLMSettings(context.Context, *connect.Request[v1.GetConversationLLMSettingsRequest]) (*connect.Response[v1.GetConversationLLMSettingsResponse], error)
	UpdateConversationLLMSettings(context.Context, *connect.Request[v1.UpdateConversationLLMSettingsRequest]) (*connect.Response[v1.UpdateConversationLLMSettingsResponse], error)
	ListAvailableModels(context.Context, *connect.Request[v1.ListAvailableModelsRequest]) (*connect.Response[v1.ListAvailableModelsResponse], error)
	// Prompt history (Dolt)
	ListPromptHistory(context.Context, *connect.Request[v1.ListPromptHistoryRequest]) (*connect.Response[v1.ListPromptHistoryResponse], error)
	DiffPrompt(context.Context, *connect.Request[v1.DiffPromptRequest]) (*connect.Response[v1.DiffPromptResponse], error)
	RevertPrompt(context.Context, *connect.Request[v1.RevertPromptRequest]) (*connect.Response[v1.RevertPromptResponse], error)
	// Tool proposals
	ListToolProposals(context.Context, *connect.Request[v1.ListToolProposalsRequest]) (*connect.Response[v1.ListToolProposalsResponse], error)
	ReviewToolProposal(context.Context, *connect.Request[v1.ReviewToolProposalRequest]) (*connect.Response[v1.ReviewToolProposalResponse], error)
	// Prompt proposals
	ListPromptProposals(context.Context, *connect.Request[v1.ListPromptProposalsRequest]) (*connect.Response[v1.ListPromptProposalsResponse], error)
	ReviewPromptProposal(context.Context, *connect.Request[v1.ReviewPromptProposalRequest]) (*connect.Response[v1.ReviewPromptProposalResponse], error)
	// Subagent profiles
	ListProfiles(context.Context, *connect.Request[v1.ListProfilesRequest]) (*connect.Response[v1.ListProfilesResponse], error)
	GetProfileOverride(context.Context, *connect.Request[v1.GetProfileOverrideRequest]) (*connect.Response[v1.GetProfileOverrideResponse], error)
	UpsertProfileOverride(context.Context, *connect.Request[v1.UpsertProfileOverrideRequest]) (*connect.Response[v1.UpsertProfileOverrideResponse], error)
	DeleteProfileOverride(context.Context, *connect.Request[v1.DeleteProfileOverrideRequest]) (*connect.Response[v1.DeleteProfileOverrideResponse], error)
	// Coder workspaces
	ListWorkspaces(context.Context, *connect.Request[v1.ListWorkspacesRequest]) (*connect.Response[v1.ListWorkspacesResponse], error)
	UpsertWorkspace(context.Context, *connect.Request[v1.UpsertWorkspaceRequest]) (*connect.Response[v1.UpsertWorkspaceResponse], error)
	DeleteWorkspace(context.Context, *connect.Request[v1.DeleteWorkspaceRequest]) (*connect.Response[v1.DeleteWorkspaceResponse], error)
	// Chat history (post-session summaries, one per (person, session)).
	ListConversationSummaries(context.Context, *connect.Request[v1.ListConversationSummariesRequest]) (*connect.Response[v1.ListConversationSummariesResponse], error)
	// Sensor proposals
	ListSensorProposals(context.Context, *connect.Request[v1.ListSensorProposalsRequest]) (*connect.Response[v1.ListSensorProposalsResponse], error)
	ReviewSensorProposal(context.Context, *connect.Request[v1.ReviewSensorProposalRequest]) (*connect.Response[v1.ReviewSensorProposalResponse], error)
	// Reset agent state — destructive: wipes persons, conversation summaries,
	// tool call log, and the Qdrant memories + task_findings collections.
	// Keeps skills, tools, providers, prompts, and settings.
	ResetAgentState(context.Context, *connect.Request[v1.ResetAgentStateRequest]) (*connect.Response[v1.ResetAgentStateResponse], error)
	// Atomic Finish for the /onboard wizard. Enrols a person with multi-pose
	// embeddings, sets agent name + voice + model, writes seeded memories.
	CompleteOnboarding(context.Context, *connect.Request[v1.CompleteOnboardingRequest]) (*connect.Response[v1.CompleteOnboardingResponse], error)
	// Set just the conversation LLM model — narrower than UpdateConversationLLMSettings,
	// for the onboarding wizard's model picker. Keeps provider/baseURL/apiKey/reasoning.
	SetConversationModel(context.Context, *connect.Request[v1.SetConversationModelRequest]) (*connect.Response[v1.SetConversationModelResponse], error)
	// Embed a face from a JPEG. Used by the onboarding wizard to capture
	// each pose embedding. Returns the 128-dim descriptor of the largest
	// detected face plus the cropped photo.
	EmbedFace(context.Context, *connect.Request[v1.EmbedFaceRequest]) (*connect.Response[v1.EmbedFaceResponse], error)
}

